class JWTError(Exception):
    """Base exception for JWT operations."""
    pass


class JWTExpiredError(JWTError):
    """Raised when a JWT token has expired."""
    pass


class JWTInvalidSignatureError(JWTError):
    """Raised when a JWT signature is invalid."""
