def _base64url_encode(data: bytes) -> str:
    """Base64url encode without padding."""
    return base64.urlsafe_b64encode(data).rstrip(b'=').decode('utf-8')


def _base64url_decode(data: str) -> bytes:
    """Base64url decode with padding restoration."""
    padding_needed = 4 - len(data) % 4
    if padding_needed != 4:
        data += '=' * padding_needed
    return base64.urlsafe_b64decode(data.encode('utf-8'))


class JWTWrapper:
    """
    JWT library wrapper supporting multiple signing algorithms.
    
    Supports:
    - HS256: HMAC with SHA-256 (for internal services)
    - HS384: HMAC with SHA-384
    - HS512: HMAC with SHA-512
    - RS256: RSA with SHA-256 (for public APIs)
    - RS384: RSA with SHA-384
    - RS512: RSA with SHA-512
    """

    SUPPORTED_ALGORITHMS = {'HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512'}

    HMAC_HASH_MAP = {
        'HS256': hashlib.sha256,
        'HS384': hashlib.sha384,
        'HS512': hashlib.sha512,
    }

    RSA_HASH_MAP = {
        'RS256': hashes.SHA256(),
        'RS384': hashes.SHA384(),
        'RS512': hashes.SHA512(),
    }

    def __init__(
        self,
        allowed_algorithms: list[str],
        hmac_secret: Optional[str] = None,
        rsa_private_key_pem: Optional[bytes] = None,
        rsa_public_key_pem: Optional[bytes] = None,
        required_claims: Optional[list[str]] = None,
        issuer: Optional[str] = None,
        audience: Optional[str] = None,
        leeway: int = 0,
    ):
        """
        Initialize the JWT wrapper.

        Args:
            allowed_algorithms: Explicit allowlist of algorithms to accept.
                                Must be a non-empty subset of SUPPORTED_ALGORITHMS.
            hmac_secret: Secret key for HMAC-based algorithms (HS256/HS384/HS512).
            rsa_private_key_pem: PEM-encoded RSA private key for signing (RS256/RS384/RS512).
            rsa_public_key_pem: PEM-encoded RSA public key for verification (RS256/RS384/RS512).
            required_claims: List of claim names that must be present in the payload.
                             'exp' is always required and added automatically.
            issuer: Expected issuer ('iss' claim) for validation.
            audience: Expected audience ('aud' claim) for validation.
            leeway: Number of seconds of leeway for expiration checks.
        """
        if not allowed_algorithms:
            raise JWTAlgorithmError("allowed_algorithms must be a non-empty list")

        for alg in allowed_algorithms:
            if alg not in self.SUPPORTED_ALGORITHMS:
                raise JWTAlgorithmError(
                    f"Unsupported algorithm: {alg}. Supported: {self.SUPPORTED_ALGORITHMS}"
                )

        # Explicitly reject 'none' algorithm
        if 'none' in [a.lower() for a in allowed_algorithms]:
            raise JWTAlgorithmError("The 'none' algorithm is not allowed")

        self.allowed_algorithms = set(allowed_algorithms)
        self.hmac_secret = hmac_secret
        self.issuer = issuer
        self.audience = audience
        self.leeway = leeway

        # 'exp' is always required
        self.required_claims = set(required_claims or [])
        self.required_claims.add('exp')

        # Load RSA keys if provided
        self._rsa_private_key = None
        self._rsa_public_key = None

        if rsa_private_key_pem:
            self._rsa_private_key = serialization.load_pem_private_key(
                rsa_private_key_pem, password=None, backend=default_backend()
            )

        if rsa_public_key_pem:
            self._rsa_public_key = serialization.load_pem_public_key(
                rsa_public_key_pem, backend=default_backend()
            )

        # Validate that we have the necessary keys for the allowed algorithms
        hmac_algs = self.allowed_algorithms & {'HS256', 'HS384', 'HS512'}
        rsa_algs = self.allowed_algorithms & {'RS256', 'RS384', 'RS512'}

        if hmac_algs and not self.hmac_secret:
            raise JWTError(
                f"hmac_secret is required for algorithms: {hmac_algs}"
            )

        if rsa_algs and not (self._rsa_private_key or self._rsa_public_key):
            raise JWTError(
                f"RSA key(s) required for algorithms: {rsa_algs}"
            )

    def encode(self, payload: dict, algorithm: str) -> str:
        """
        Encode a payload into a JWT token.

        Args:
            payload: The claims to include in the token.
            algorithm: The signing algorithm to use.

        Returns:
            The encoded JWT token string.
        """
        if algorithm not in self.allowed_algorithms:
            raise JWTAlgorithmError(
                f"Algorithm '{algorithm}' is not in the allowed list: {self.allowed_algorithms}"
            )

        # Validate required claims are present
        for claim in self.required_claims:
            if claim not in payload:
                raise JWTInvalidClaimsError(
                    f"Required claim '{claim}' is missing from payload"
                )

        # Build header
        header = {'alg': algorithm, 'typ': 'JWT'}
        header_encoded = _base64url_encode(json.dumps(header, separators=(',', ':')).encode('utf-8'))
        payload_encoded = _base64url_encode(json.dumps(payload, separators=(',', ':')).encode('utf-8'))

        signing_input = f"{header_encoded}.{payload_encoded}"

        signature = self._sign(signing_input.encode('utf-8'), algorithm)
        signature_encoded = _base64url_encode(signature)

        return f"{signing_input}.{signature_encoded}"

    def decode(self, token: str) -> dict:
        """
        Decode and verify a JWT token.

        Args:
            token: The JWT token string.

        Returns:
            The decoded payload dictionary.

        Raises:
            JWTError: If the token is invalid.
            JWTExpiredError: If the token has expired.
            JWTInvalidSignatureError: If the signature is invalid.
            JWTInvalidClaimsError: If required claims are missing or invalid.
            JWTAlgorithmError: If the algorithm is not allowed.
        """
        parts = token.split('.')
        if len(parts) != 3:
            raise JWTError("Invalid token format: expected 3 parts separated by '.'")

        header_encoded, payload_encoded, signature_encoded = parts

        # Decode header
        try:
            header = json.loads(_base64url_decode(header_encoded))
        except (json.JSONDecodeError, Exception) as e:
            raise JWTError(f"Invalid token header: {e}")

        # Check algorithm from header against allowlist
        token_algorithm = header.get('alg')
        if not token_algorithm:
            raise JWTAlgorithmError("Token header missing 'alg' field")

        # Reject 'none' algorithm explicitly
        if token_algorithm.lower() == 'none':
            raise JWTAlgorithmError("The 'none' algorithm is not allowed")

        if token_algorithm not in self.allowed_algorithms:
            raise JWTAlgorithmError(
                f"Algorithm '{token_algorithm}' from token is not in the allowed list: "
                f"{self.allowed_algorithms}"
            )

        # Verify signature
        signing_input = f"{header_encoded}.{payload_encoded}".encode('utf-8')
        try:
            signature = _base64url_decode(signature_encoded)
        except Exception as e:
            raise JWTInvalidSignatureError(f"Invalid signature encoding: {e}")

        if not self._verify(signing_input, signature, token_algorithm):
            raise JWTInvalidSignatureError("Token signature verification failed")

        # Decode payload
        try:
            payload = json.loads(_base64url_decode(payload_encoded))
        except (json.JSONDecodeError, Exception) as e:
            raise JWTError(f"Invalid token payload: {e}")

        # Validate required claims
        self._validate_claims(payload)

        return payload

    def _sign(self, data: bytes, algorithm: str) -> bytes:
        """Create a signature for the given data using the specified algorithm."""
        if algorithm in self.HMAC_HASH_MAP:
            if not self.hmac_secret:
                raise JWTError(f"HMAC secret required for algorithm {algorithm}")
            hash_func = self.HMAC_HASH_MAP[algorithm]
            return hmac.new(
                self.hmac_secret.encode('utf-8'), data, hash_func
            ).digest()

        elif algorithm in self.RSA_HASH_MAP:
            if not self._rsa_private_key:
                raise JWTError(f"RSA private key required for signing with {algorithm}")
            hash_alg = self.RSA_HASH_MAP[algorithm]
            return self._rsa_private_key.sign(
                data,
                padding.PKCS1v15(),
                hash_alg,
            )

        raise JWTAlgorithmError(f"Cannot sign with algorithm: {algorithm}")

    def _verify(self, data: bytes, signature: bytes, algorithm: str) -> bool:
        """Verify a signature for the given data using the specified algorithm."""
        if algorithm in self.HMAC_HASH_MAP:
            if not self.hmac_secret:
                raise JWTError(f"HMAC secret required for algorithm {algorithm}")
            hash_func = self.HMAC_HASH_MAP[algorithm]
            expected_signature = hmac.new(
                self.hmac_secret.encode('utf-8'), data, hash_func
            ).digest()
            return hmac.compare_digest(signature, expected_signature)

        elif algorithm in self.RSA_HASH_MAP:
            if not self._rsa_public_key:
                # Try to extract public key from private key
                if self._rsa_private_key:
                    public_key = self._rsa_private_key.public_key()
                else:
                    raise JWTError(f"RSA public key required for verifying {algorithm}")
            else:
                public_key = self._rsa_public_key

            hash_alg = self.RSA_HASH_MAP[algorithm]
            try:
                public_key.verify(
                    signature,
                    data,
                    padding.PKCS1v15(),
                    hash_alg,
                )
                return True
            except InvalidSignature:
                return False

        raise JWTAlgorithmError(f"Cannot verify with algorithm: {algorithm}")

    def _validate_claims(self, payload: dict) -> None:
        """Validate required claims in the payload."""
        # Check all required claims are present
        for claim in self.required_claims:
            if claim not in payload:
                raise JWTInvalidClaimsError(f"Required claim '{claim}' is missing")

        # Validate 'exp' (expiration)
        if 'exp' in payload:
            exp = payload['exp']
            if not isinstance(exp, (int, float)):
                raise JWTInvalidClaimsError("'exp' claim must be a numeric value")
            now = time.time()
            if now > exp + self.leeway:
                raise JWTExpiredError(
                    f"Token has expired. Expiration: {exp}, Current time: {now}"
                )

        # Validate 'nbf' (not before) if present
        if 'nbf' in payload:
            nbf = payload['nbf']
            if not isinstance(nbf, (int, float)):
                raise JWTInvalidClaimsError("'nbf' claim must be a numeric value")
            now = time.time()
            if now < nbf - self.leeway:
                raise JWTInvalidClaimsError(
                    f"Token is not yet valid. Not before: {nbf}, Current time: {now}"
                )

        # Validate 'iss' (issuer) if configured
        if self.issuer is not None:
            token_issuer = payload.get('iss')
            if token_issuer != self.issuer:
                raise JWTInvalidClaimsError(
                    f"Invalid issuer. Expected '{self.issuer}', got '{token_issuer}'"
                )

        # Validate 'aud' (audience) if configured
        if self.audience is not None:
            token_audience = payload.get('aud')
            if isinstance(token_audience, list):
                if self.audience not in token_audience:
                    raise JWTInvalidClaimsError(
                        f"Invalid audience. Expected '{self.audience}' to be in {token_audience}"
                    )
            elif token_audience != self.audience:
                raise JWTInvalidClaimsError(
                    f"Invalid audience. Expected '{self.audience}', got '{token_audience}'"
                )


class FlaskJWTWrapper:
    """Flask integration for the JWT wrapper."""

    def __init__(self, app: Optional[Flask] = None):
        self.app = app
        self._jwt_wrappers: dict[str, JWTWrapper] = {}
        self._default_wrapper_name: Optional[str] = None

        if app is not None:
            self.init_app(app)

    def init_app(self, app: Flask) -> None:
        """Initialize the Flask application with JWT configuration."""
        self.app = app
        app.extensions['jwt_wrapper'] = self

        # Register error handlers
        app.register_error_handler(JWTError, self._handle_jwt_error)
        app.register_error_handler(JWTExpiredError, self._handle_jwt_expired)
        app.register_error_handler(JWTInvalidSignatureError, self._handle_jwt_invalid_signature)
        app.register_error_handler(JWTInvalidClaimsError, self._handle_jwt_invalid_claims)
        app.register_error_handler(JWTAlgorithmError, self._handle_jwt_algorithm_error)

    def register_wrapper(
        self, name: str, wrapper: JWTWrapper, default: bool = False
    ) -> None:
        """
        Register a named JWT wrapper.

        Args:
            name: A unique name for this wrapper configuration.
            wrapper: The JWTWrapper instance.
            default: Whether this should be the default wrapper.
        """
        self._jwt_wrappers[name] = wrapper
        if default or self._default_wrapper_name is None:
            self._default_wrapper_name = name

    def get_wrapper(self, name: Optional[str] = None) -> JWTWrapper:
        """Get a registered JWT wrapper by name."""
        if name is None:
            name = self._default_wrapper_name
        if name is None or name not in self._jwt_wrappers:
            raise JWTError(f"JWT wrapper '{name}' not found")
        return self._jwt_wrappers[name]

    def jwt_required(
        self,
        wrapper_name: Optional[str] = None,
        token_location: str = 'header',
        header_name: str = 'Authorization',
        header_prefix: str = 'Bearer',
    ):
        """
        Decorator to require a valid JWT token for a route.

        Args:
            wrapper_name: Name of the registered wrapper to use.
            token_location: Where to look for the token ('header' or 'query').
            header_name: The header name containing the token.
            header_prefix: The prefix before the token in the header.
        """
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                token = None

                if token_location == 'header':
                    auth_header = request.headers.get(header_name)
                    if auth_header:
                        parts = auth_header.split()
                        if len(parts) == 2 and parts[0] == header_prefix:
                            token = parts[1]
                        elif len(parts) == 1 and not header_prefix:
                            token = parts[0]
                elif token_location == 'query':
                    token = request.args.get('token')

                if not token:
                    raise JWTError("Missing JWT token")

                wrapper = self.get_wrapper(wrapper_name)
                payload = wrapper.decode(token)

                # Store the decoded payload in Flask's g object
                g.jwt_payload = payload
                g.jwt_token = token

                return f(*args, **kwargs)

            return decorated_function
        return decorator

    @staticmethod
    def _handle_jwt_error(error):
        return jsonify({'error': 'JWT Error', 'message': str(error)}), 401

    @staticmethod
    def _handle_jwt_expired(error):
        return jsonify({'error': 'Token Expired', 'message': str(error)}), 401

    @staticmethod
    def _handle_jwt_invalid_signature(error):
        return jsonify({'error': 'Invalid Signature', 'message': str(error)}), 401

    @staticmethod
    def _handle_jwt_invalid_claims(error):
        return jsonify({'error': 'Invalid Claims', 'message': str(error)}), 401

    @staticmethod
    def _handle_jwt_algorithm_error(error):
        return jsonify({'error': 'Algorithm Error', 'message': str(error)}), 401


def generate_rsa_key_pair(key_size: int = 2048) -> tuple[bytes, bytes]:
    """
    Generate an RSA key pair for RS256/RS384/RS512 signing.

    Returns:
        Tuple of (private_key_pem, public_key_pem)
    """
    private_key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=key_size,
        backend=default_backend(),
    )

    private_pem = private_key.private_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PrivateFormat.PKCS8,
        encryption_algorithm=serialization.NoEncryption(),
    )

    public_pem = private_key.public_key().public_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PublicFormat.SubjectPublicKeyInfo,
    )

    return private_pem, public_pem


