def create_example_app() -> Flask:
    """Create an example Flask application demonstrating the JWT wrapper."""
    app = Flask(__name__)

    # Generate RSA keys for the example
    rsa_private_pem, rsa_public_pem = generate_rsa_key_pair()

    # Create JWT wrappers for different use cases
    internal_wrapper = JWTWrapper(
        allowed_algorithms=['HS256'],
        hmac_secret='super-secret-internal-key-change-in-production',
        required_claims=['exp', 'sub', 'service'],
        issuer='internal-auth-service',
        leeway=5,
    )

    public_wrapper = JWTWrapper(
        allowed_algorithms=['RS256'],
        rsa_private_key_pem=rsa_private_pem,
        rsa_public_key_pem=rsa_public_pem,
        required_claims=['exp', 'sub'],
        issuer='public-auth-service',
        audience='api.example.com',
        leeway=10,
    )

    # Multi-algorithm wrapper that accepts both (for gateway services)
    gateway_wrapper = JWTWrapper(
        allowed_algorithms=['HS256', 'RS256'],
        hmac_secret='super-secret-internal-key-change-in-production',
        rsa_public_key_pem=rsa_public_pem,
        required_claims=['exp', 'sub'],
        leeway=10,
    )

    # Initialize Flask JWT integration
    flask_jwt = FlaskJWTWrapper(app)
    flask_jwt.register_wrapper('internal', internal_wrapper, default=True)
    flask_jwt.register_wrapper('public', public_wrapper)
    flask_jwt.register_wrapper('gateway', gateway_wrapper)

    @app.route('/generate/internal', methods=['POST'])
    def generate_internal_token():
        """Generate an internal service token (HS256)."""
        payload = {
            'sub': 'user-123',
            'service': 'user-service',
            'iss': 'internal-auth-service',
            'exp': int(time.time()) + 3600,
            'iat': int(time.time()),
        }
        token = internal_wrapper.encode(payload, 'HS256')
        return jsonify({'token': token, 'algorithm': 'HS256'})

    @app.route('/generate/public', methods=['POST'])
    def generate_public_token():
        """Generate a public API token (RS256)."""
        payload = {
            'sub': 'user-456',
            'iss': 'public-auth-service',
            'aud': 'api.example.com',
            'exp': int(time.time()) + 3600,
            'iat': int(time.time()),
            'roles': ['read', 'write'],
        }
        token = public_wrapper.encode(payload, 'RS256')
        return jsonify({'token': token, 'algorithm': 'RS256'})

    @app.route('/internal/resource')
    @flask_jwt.jwt_required(wrapper_name='internal')
    def internal_resource():
        """Protected internal resource requiring HS256 token."""
        return jsonify({
            'message': 'Internal resource accessed successfully',
            'user': g.jwt_payload.get('sub'),
            'service': g.jwt_payload.get('service'),
        })

    @app.route('/public/resource')
    @flask_jwt.jwt_required(wrapper_name='public')
    def public_resource():
        """Protected public resource requiring RS256 token."""
        return jsonify({
            'message': 'Public resource accessed successfully',
            'user': g.jwt_payload.get('sub'),
            'roles': g.jwt_payload.get('roles', []),
        })

    @app.route('/gateway/resource')
    @flask_jwt.jwt_required(wrapper_name='gateway')
    def gateway_resource():
        """Gateway resource accepting both HS256 and RS256 tokens."""
        return jsonify({
            'message': 'Gateway resource accessed successfully',
            'user': g.jwt_payload.get('sub'),
            'payload': g.jwt_payload,
        })

    @app.route('/health')
    def health():
        return jsonify({'status': 'healthy'})

    return app


if __name__ == '__main__':
    app = create_example_app()
    app.run(debug=True, port=5000)